}

//! # Brique 0 : SecureMemGuard
//!
//! Cette crate implémente le niveau fondamental de sécurité "Zero-Trust" de la Ruche R2D2.
//! Elle fournit le wrapper `SecureMemGuard<T>` garantissant que toute donnée sensible
//! (fragments non validés, clés cryptographiques, poids d'inférence)
//! est physiquement écrasée (Zeroization) en mémoire dès que la variable sort du scope.
//!
//! Ceci empêche le *Memory Scraping* et l'exposition des canaux auxiliaires (Side Channel).

use secrecy::{ExposeSecret, SecretBox};
use thiserror::Error;
use zeroize::Zeroize;

/// Erreurs liées à la gestion de la mémoire sécurisée.
#[derive(Debug, Error)]
pub enum SecureMemError {
    #[error("Tentative d'accès à une mémoire non initialisée ou révoquée")]
    RevokedAccess,
    #[error("Erreur de conversion mémoire sécurisée: {0}")]
    ConversionError(String),
}

/// Un garde mémoire sécurisé qui efface de la RAM son contenu à la destruction.
///
/// Ce conteneur "Zero-Trust" alloue l'information et s'assure qu'un appel
/// `explicit_bzero` (ou équivalent) est invoqué par le compilateur
/// lorsque la donnée n'est plus utile.
#[derive(Debug)]
pub struct SecureMemGuard<T>
where
    T: Zeroize + Clone,
{
    // Utilisé pour stocker des données dynamiques qui sont systématiquement nettoyées.
    inner: SecretBox<T>,
}

impl<T> SecureMemGuard<T>
where
    T: Zeroize + Clone,
{
    /// Alloue un nouveau bloc mémoire sécurisé.
    ///
    /// # Exemple
    ///
    /// ```rust
    /// use zeroize::ZeroizeOnDrop;
    /// use zeroize::Zeroize;
    /// use r2d2_secure_mem::SecureMemGuard;
    ///
    /// #[derive(Clone, Zeroize, ZeroizeOnDrop)]
    /// struct SecretData(String);
    ///
    /// let guard = SecureMemGuard::new(SecretData("Données Hautement Sensibles".to_string()));
    /// // À la fin du bloc, "Données Hautement Sensibles" est détruit physiquement de la RAM.
    /// ```
    pub fn new(data: T) -> Self {
        Self {
            inner: SecretBox::new(Box::new(data)),
        }
    }

    /// Expose temporairement la valeur pour un traitement immédiat.
    ///
    /// L'appelant doit faire passer cette référence à une fonction (ex: Paradox Engine).
    pub fn expose_payload(&self) -> &T {
        self.inner.expose_secret()
    }
}

//! # Brique 1: JSONAI v3.1
//! Standard de représentation sémantique stricte.
//!
//! Implémente le typage de la vérité et l'état de croyance selon le Livre Blanc R2D2.

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use zeroize::Zeroize;

/// Identité de l'agent ou du module ayant produit le fragment.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub enum AgentSource {
    Vision(String), // ex: "Gemini 2.5 Pro"
    Audio(String),  // ex: "Whisper C++"
    OCR(String),    // ex: "Tesseract"
    ParadoxEngine,  // Le solveur interne
    System,
}

/// État de croyance d'un fragment d'information.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub enum BeliefState {
    /// Fait mathématique, physique ou numérique avéré
    Fact,
    /// Synthèse probabiliste, opinion ou hypothèse
    Perspective,
}

/// Niveau de résolution du consensus épistémologique.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub enum ConsensusLevel {
    /// Jamais débattu
    Raw,
    /// Débattu, avec des contradictions résiduelles
    DebatedSynthesis,
    /// Accord unanime et non-contradictoire
    ConsensusReached,
}

/// Relation sémantique forte entre deux fragments.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub enum OntologyRel {
    Requires,
    Entails,
    IsStepOf,
    Contradicts,
}

/// Traçabilité absolue du JSONAI v3.1.
///
/// Ne contient PAS de `ZeroizeOnDrop` car cette structure est conçue pour
/// être stockée dans la Rust mémoire standard avant d'être validée et convertie.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct JsonAiV3 {
    pub id: String,
    pub source: AgentSource,
    pub timestamp: DateTime<Utc>,

    pub is_fact: bool,
    pub belief_state: BeliefState,
    pub consensus: ConsensusLevel,

    pub content: String,

    pub ontological_tags: Vec<OntologyRel>,
    pub dependencies: Vec<String>,
}

impl JsonAiV3 {
    pub fn new(
        id: String,
        source: AgentSource,
        content: String,
        belief_state: BeliefState,
    ) -> Self {
        Self {
            id,
            source,
            timestamp: Utc::now(),
            is_fact: belief_state == BeliefState::Fact,
            belief_state,
            consensus: ConsensusLevel::Raw,
            content,
            ontological_tags: Vec::new(),
            dependencies: Vec::new(),
        }
    }
}

// Implémentation manuelle de Zeroize pour permettre l'encapsulation dans le typestate
impl Zeroize for JsonAiV3 {
    fn zeroize(&mut self) {
        self.id.zeroize();
        self.content.zeroize();
        for dep in &mut self.dependencies {
            dep.zeroize();
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_jsonai_serialization() {
        let jsonai = JsonAiV3::new(
            "test_123".to_string(),
            AgentSource::System,
            "Ceci est un test".to_string(),
            BeliefState::Fact,
        );

        let serialized = serde_json::to_string(&jsonai).unwrap();
        assert!(serialized.contains("test_123"));
        assert!(serialized.contains("Ceci est un test"));
    }
}

//! # Brique 3: Paradox Engine
//! Moteur de validation logique et de consensus.
//!
//! Reçoit un fragment `Unverified` depuis le Kernel, valide sa cohérence
//! interne et externe, et retourne une preuve d'inférence autorisant le passage
//! au typestate `Validated`.

use r2d2_jsonai::{ConsensusLevel, JsonAiV3};
use r2d2_kernel::{KernelError, TruthValidator};
use thiserror::Error;
use tracing::{info, warn};

#[derive(Debug, Error)]
pub enum ParadoxError {
    #[error("Contradiction logique détectée: {0}")]
    ContradictionDetected(String),
    #[error("Consensus insuffisant pour validation")]
    InsufficientConsensus,
}

/// Transforme les erreurs du Paradox Engine en erreurs Kernel compatibles
impl From<ParadoxError> for KernelError {
    fn from(error: ParadoxError) -> Self {
        KernelError::ValidationFailed(error.to_string())
    }
}

/// Moteur de résolution des contradictions.
pub struct ParadoxSolver;

impl TruthValidator for ParadoxSolver {
    #[tracing::instrument(skip(self, payload), fields(payload_len = payload.len()))]
    fn validate_payload(&self, payload: &str) -> Result<(String, String), KernelError> {
        info!("Début de l'analyse Paradox sur un fragment Unverified.");

        // On tente de parser la structure de données formelle.
        let mut jsonai: JsonAiV3 = serde_json::from_str(payload).map_err(|e| {
            ParadoxError::ContradictionDetected(format!("Erreur de parsing JSONAI: {}", e))
        })?;

        // Règle 1: Un fait ne peut pas être contredit
        if jsonai.is_fact && !jsonai.ontological_tags.is_empty() {
            warn!(
                "Validation stricte: un fait absolu est analysé à travers ses tags ontologiques."
            );
        }

        // Règle 2: Élévation du consensus une fois les axiomes vérifiés
        jsonai.consensus = ConsensusLevel::ConsensusReached;

        // On sérialise la donnée de nouveau, avec son niveau de consensus mis à jour.
        let verified_payload = serde_json::to_string(&jsonai).map_err(|e| {
            ParadoxError::ContradictionDetected(format!("Erreur SérialiZation: {}", e))
        })?;

        let proof_of_inference = format!("POI_SAT_SOLVED_{}", jsonai.id);
        info!(
            "Analyse terminée. Consensus atteint sans paradoxe. [{}]",
            proof_of_inference
        );

        Ok((verified_payload, proof_of_inference))
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use r2d2_jsonai::{AgentSource, BeliefState};

    #[test]
    fn test_paradox_solver() {
        let jsonai = JsonAiV3::new(
            "test_123".to_string(),
            AgentSource::System,
            "Vérité axiomatique".to_string(),
            BeliefState::Fact,
        );
        let payload = serde_json::to_string(&jsonai).unwrap();

        let solver = ParadoxSolver;
        let (verified, poi) = solver.validate_payload(&payload).expect("Doit valider");

        let verified_json: JsonAiV3 = serde_json::from_str(&verified).unwrap();
        assert_eq!(verified_json.consensus, ConsensusLevel::ConsensusReached);
        assert!(poi.starts_with("POI_SAT_SOLVED_test_123"));
    }
}
